'use client';

import { useState } from 'react';
import { createClient } from '@/lib/supabase/client';
import { User } from 'lucide-react';

export function LoginForm() {
    const [email, setEmail] = useState('');
    const [status, setStatus] = useState<'idle' | 'loading' | 'success' | 'error'>('idle');
    const [errorMessage, setErrorMessage] = useState('');

    const supabase = createClient();

    const handleMagicLink = async (e: React.FormEvent) => {
        e.preventDefault();
        setStatus('loading');
        setErrorMessage('');

        const { error } = await supabase.auth.signInWithOtp({
            email,
            options: {
                // Redirecționează utilizatorul direct spre pagina privată după validarea din email
                emailRedirectTo: `${window.location.origin}/patient`,
            },
        });

        if (error) {
            setStatus('error');
            setErrorMessage(error.message);
        } else {
            setStatus('success');
        }
    };

    const handleProviderLogin = async (provider: 'google' | 'apple') => {
        setStatus('loading');
        await supabase.auth.signInWithOAuth({
            provider,
            options: {
                redirectTo: `${window.location.origin}/patient`,
            },
        });
    };

    return (
        <div className="w-full max-w-md animate-in fade-in zoom-in-95 duration-500">
            <div className="rounded-2xl border border-neutral-200 bg-white/70 backdrop-blur-xl p-8 shadow-2xl">
                <div className="mb-8 text-center">
                    <div className="mx-auto flex h-12 w-12 items-center justify-center rounded-full bg-primary-100 mb-4">
                        <User className="h-6 w-6 text-primary-600" />
                    </div>
                    <h1 className="text-2xl font-bold tracking-tight text-neutral-900">Autentificare</h1>
                    <p className="mt-2 text-sm text-neutral-500">Accesează dosarul tău medical sau panoul de control.</p>
                </div>

                {status === 'success' ? (
                    <div className="rounded-lg bg-green-50 p-4 text-center">
                        <p className="text-sm font-medium text-green-800">Ți-am trimis un link securizat!</p>
                        <p className="mt-1 text-xs text-green-600">Verifică inbox-ul (inclusiv folderul Spam) pentru adresa {email}.</p>
                    </div>
                ) : (
                    <>
                        <form onSubmit={handleMagicLink} className="space-y-4">
                            <div>
                                <label htmlFor="email" className="sr-only">Adresă de email</label>
                                <input
                                    id="email"
                                    type="email"
                                    required
                                    value={email}
                                    onChange={(e) => setEmail(e.target.value)}
                                    placeholder="nume@exemplu.ro"
                                    className="block w-full rounded-xl border border-neutral-200 bg-white px-4 py-3 text-neutral-900 placeholder-neutral-400 focus:border-primary-500 focus:outline-none focus:ring-4 focus:ring-primary-500/10 transition-all"
                                    autoComplete="email"
                                    disabled={status === 'loading'}
                                />
                            </div>

                            {status === 'error' && (
                                <p className="text-sm text-rose-600">{errorMessage}</p>
                            )}

                            <button
                                type="submit"
                                disabled={status === 'loading' || !email}
                                className="flex w-full items-center justify-center rounded-xl bg-primary-600 px-4 py-3 text-sm font-medium text-white shadow-sm hover:bg-primary-700 focus:outline-none focus:ring-4 focus:ring-primary-600/20 disabled:opacity-50 disabled:cursor-not-allowed transition-all"
                            >
                                {status === 'loading' ? 'Se procesează...' : 'Autentificare prin Email (BETA)'}
                            </button>
                        </form>

                        <div className="relative my-8">
                            <div className="absolute inset-0 flex items-center" aria-hidden="true">
                                <div className="w-full border-t border-neutral-200" />
                            </div>
                            <div className="relative flex justify-center">
                                <span className="bg-white px-3 text-xs font-medium text-neutral-500 uppercase tracking-widest">sau conectare rapidă</span>
                            </div>
                        </div>

                        <div className="space-y-3">
                            <button
                                type="button"
                                onClick={() => handleProviderLogin('google')}
                                disabled={status === 'loading'}
                                className="flex w-full items-center justify-center gap-3 rounded-xl border border-neutral-200 bg-white px-4 py-3 text-sm font-medium text-neutral-700 shadow-sm hover:bg-neutral-50 focus:outline-none focus:ring-4 focus:ring-neutral-500/10 transition-all disabled:opacity-50"
                            >
                                <img src="https://authjs.dev/img/providers/google.svg" alt="Google" className="h-5 w-5" />
                                Continuă cu Google
                            </button>
                        </div>
                    </>
                )}
            </div>

            <p className="mt-6 text-center text-xs text-neutral-500">
                Prin autentificare ești de acord cu <a href="/termeni-si-conditii" className="underline hover:text-primary-600 focus:outline-none">Termenii și Condițiile</a> noastre. Sistem protejat la standard HIPAA.
            </p>
        </div>
    );
}
